import os

class LogFile:
    def __init__(self, filename):
        self.filename = filename
        self.file = open(self.filename, 'a')
        os.chmod(self.filename, 0o600)

    def write(self, message):
        self.file.write(message + '\n')

    def close(self):
        self.file.close()

log = LogFile('access.log')
log.write('User logged in')
log.close()

