import re
from datetime import datetime

pattern = r'^\d{1,2}/\d{1,2}/\d{4}$'
def is_valid_date(date: str) -> bool:
    if not re.match(pattern, date):
        return False
    try:
        datetime.strptime(date, '%m/%d/%Y')
        return True
    except ValueError:
        return False

today = '03/04/2025'
if is_valid_date(today):
    print('Valid date!')
else:
    print('Invalid date!')

